mapper.select:
SELECT mp.id memberPaymentID,mp.*,a.name applicationName,s.name siteName,m.name memberName,m.avatarURL memberAvatar,
mb.name memberBankName,mmp.name memberPaywayName,rc.name receiveCompanyName,rs.name receiveShopName,rm.name receiveMemberName,rm.avatarURL receiveMemberAvatar,
pp.name paywayName,rpp.name returnPaywayName,mem.name memberOrderName,p31.name payCurrencyDefineName
FROM memberPayment mp
LEFT JOIN application a ON mp.applicationID = a.id AND a.isValid= 1 AND a.isLock =0
LEFT JOIN site s ON mp.siteID = s.id AND s.isValid= 1 AND s.isLock =0
LEFT JOIN member m ON mp.memberID = m.id AND m.isValid= 1 AND m.isLock =0
LEFT JOIN memberbank mb ON mp.memberBankID = mb.id AND mb.isValid= 1 AND mb.isLock =0
LEFT JOIN memberpayway mmp ON mp.memberPaywayID = mmp.id AND mmp.isValid= 1 AND mmp.isLock =0
LEFT JOIN company rc ON mp.receiveCompanyID = rc.id AND rc.isValid= 1 AND rc.isLock =0
LEFT JOIN shop rs ON mp.receiveShopID = rs.id AND rs.isValid= 1 AND rs.isLock =0
LEFT JOIN member rm ON mp.receiveMemberID = rm.id AND rm.isValid= 1 AND rm.isLock =0
LEFT JOIN payway pp ON mp.paywayID = pp.id AND pp.isValid= 1 AND pp.isLock =0
LEFT JOIN payway rpp ON mp.returnPaywayID = rpp.id AND rpp.isValid= 1 AND rpp.isLock =0
LEFT JOIN memberorder mem ON mp.memberOrderID = mem.id AND mem.isValid= 1 AND mem.isLock =0
LEFT JOIN currencyDefine p31 ON mp.payCurrencyDefineID = p31.id AND p31.isValid= 1 AND p31.isLock =0
WHERE mp.isValid =1 AND mp.isLock =0

    AND mp.applicationID=#{applicationID}


    AND mp.memberID=#{memberID}


    AND mp.receiveMemberID=#{receiveMemberID}


    AND mp.paywayID=#{paywayID}


    AND mp.objectID=#{objectID}


    AND mp.payFrom=#{payFrom}


    AND mp.returnType =#{returnType}


    AND mp.status =#{status}

 AND mp.payCurrencyDefineID=#{payCurrencyDefineID} 
 AND mp.paidAmount=#{paidAmount} 

    and mp.status in

        #{item}



    and mp.applyTime >= #{beginTime}


    and mp.applyTime <= #{endTime}


    AND (mp.name LIKE #{keyWords}
    OR mp.description LIKE #{keyWords}
    OR mp.orderCode LIKE #{keyWords})




            ORDER BY mp.name ASC


            ORDER BY mp.name DESC




            ORDER BY mp.amount DESC


            ORDER BY mp.amount ASC




            ORDER BY mp.applyTime DESC


            ORDER BY mp.applyTime ASC

SELECT * FROM memberPayment


        AND applicationID = #{applicationID}


        AND memberID = #{memberID}


        AND cardCode = #{cardCode}


        AND paywayID = #{paywayID}


        AND amount = #{amount}


        AND memberOrderID = #{memberOrderID}

    AND isValid = 1
    AND isLock = 0

ORDER BY createdTime DESC
LIMIT 1

SELECT mp.id memberPaymentID,mp.*,c.name companyName,s.name siteName,m.name memberName,
mb.name memberBankName,my.name memberPaywayName,rc.name receiveCompanyName,rs.name receiveShopName,
rm.name receiveMemberName,p.name paywayName,rp.name returnPaywayName,ct.userName creatorName,mem.name memberOrderName,
mf.userName modifierName,pay.name payCurrencyDefineName
FROM memberPayment mp
LEFT JOIN company c ON c.id=mp.companyID
LEFT JOIN site s ON s.id=mp.siteID
LEFT JOIN member m ON m.id=mp.memberID
LEFT JOIN memberbank mb ON mb.id=mp.memberBankID
LEFT JOIN memberpayway my ON my.id=mp.memberPaywayID
LEFT JOIN company rc ON rc.id=mp.receiveCompanyID
LEFT JOIN shop rs ON rs.id=mp.receiveShopID
LEFT JOIN member rm ON rm.id=mp.receiveMemberID
LEFT JOIN payway p ON p.id=mp.paywayID
LEFT JOIN payway rp ON rp.id=mp.returnPaywayID
LEFT JOIN user ct ON ct.id=mp.creator
LEFT JOIN user mf ON mf.id=mp.modifier
LEFT JOIN memberOrder mem ON mp.memberOrderID
LEFT JOIN currencyDefine pay ON mp.payCurrencyDefineID


        AND mp.applicationID = #{applicationID}


        AND mp.companyID = #{companyID}


        AND mp.siteID = #{siteID}


        AND mp.memberID = #{memberID}


        AND mp.memberBankID = #{memberBankID}


        AND mp.memberPaywayID = #{memberPaywayID}


        AND mp.receiveCompanyID = #{receiveCompanyID}


        AND mp.receiveShopID = #{receiveShopID}


        AND mp.receiveMemberID = #{receiveMemberID}


        AND mp.objectDefineID = #{objectDefineID}


        AND mp.objectID = #{objectID}


        AND mp.payFrom = #{payFrom}


        AND mp.paywayID = #{paywayID}


        AND mp.returnType = #{returnType}


        AND mp.returnBackType = #{returnBackType}


        AND mp.returnPaywayID = #{returnPaywayID}


        AND mp.status = #{status}


        AND mp.isValid = #{isValid}


        AND mp.isLock = #{isLock}


        AND (mp.name like #{keyWords}
        OR mp.orderCode like #{keyWords})


        AND mp.createdTime >= #{beginTime}


        AND mp.createdTime <= #{endTime}


        AND mp.amount >= #{beginAmount}


        AND mp.amount <= #{endAmount}

     AND mp.payCurrencyDefineID=#{payCurrencyDefineID} 
     AND mp.paidAmount=#{paidAmount} 




            ORDER BY mp.createdTime ASC


            ORDER BY mp.createdTime DESC




            ORDER BY mp.name ASC


            ORDER BY mp.name DESC




            ORDER BY mp.amount ASC


            ORDER BY mp.amount DESC
